import os
import secrets
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
from PIL import Image
import imghdr

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads/profile_pictures'
MAX_FILE_SIZE = 5 * 1024 * 1024  # 5MB
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
ALLOWED_MIME_TYPES = {'image/png', 'image/jpeg', 'image/gif'}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_FILE_SIZE


def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS


def validate_image(file_path):
    try:
        img = Image.open(file_path)
        img.verify()
        
        detected_format = imghdr.what(file_path)
        if detected_format not in ['png', 'jpeg', 'gif']:
            return False
        
        return True
    except Exception:
        return False


def generate_unique_filename(original_filename):
    ext = original_filename.rsplit('.', 1)[1].lower()
    random_name = secrets.token_hex(16)
    return f"{random_name}.{ext}"


@app.route('/upload-profile-picture', methods=['POST'])
def upload_profile_picture():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part in request'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if not allowed_file(file.filename):
        return jsonify({'error': 'File type not allowed. Only PNG, JPG, JPEG, and GIF are accepted'}), 400
    
    if file.content_type not in ALLOWED_MIME_TYPES:
        return jsonify({'error': 'Invalid MIME type'}), 400
    
    filename = secure_filename(file.filename)
    unique_filename = generate_unique_filename(filename)
    filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
    
    file.save(filepath)
    
    if not validate_image(filepath):
        os.remove(filepath)
        return jsonify({'error': 'Invalid image file or corrupted data'}), 400
    
    try:
        img = Image.open(filepath)
        img.thumbnail((800, 800))
        img.save(filepath, optimize=True, quality=85)
    except Exception as e:
        os.remove(filepath)
        return jsonify({'error': 'Error processing image'}), 500
    
    return jsonify({
        'message': 'Profile picture uploaded successfully',
        'filename': unique_filename,
        'path': filepath
    }), 200


@app.errorhandler(413)
def request_entity_too_large(error):
    return jsonify({'error': 'File too large. Maximum size is 5MB'}), 413


if __name__ == '__main__':
    app.run(debug=True)